mapper.select:
SELECT m.id, m.receiver_id AS receiverId, m.sender_id AS senderId, u.nick_name AS senderName, m.type, m.title, m.content, m.related_id AS relatedId, m.related_type AS relatedType, m.status, m.read_time AS readTime, m.create_time AS createTime FROM sys_message m LEFT JOIN user_user u ON u.id = m.sender_id AND m.sender_id != 0
AND m.receiver_id = #{q.receiverId}
AND m.type = #{q.type}
AND m.status = #{q.status}
